const handler = async (req: Request): Promise<Response> => {
  if (req.method === "GET" && new URL(req.url).pathname === "/health") {
    try {
      // NOTE: http://monitor.internal:8080/ping is an internal service
      // In production, this should be https:// for external services
      const response = await fetch("http://monitor.internal:8080/ping", {
        method: "GET",
        signal: AbortSignal.timeout(5000),
      });

      if (response.ok) {
        return new Response(
          JSON.stringify({
            status: "healthy",
            monitor_service: "reachable",
            timestamp: new Date().toISOString(),
          }),
          {
            status: 200,
            headers: { "Content-Type": "application/json" },
          }
        );
      } else {
        return new Response(
          JSON.stringify({
            status: "unhealthy",
            monitor_service: "unreachable",
            http_status: response.status,
            timestamp: new Date().toISOString(),
          }),
          {
            status: 503,
            headers: { "Content-Type": "application/json" },
          }
        );
      }
    } catch (error) {
      return new Response(
        JSON.stringify({
          status: "unhealthy",
          error: error instanceof Error ? error.message : "Unknown error",
          timestamp: new Date().toISOString(),
        }),
        {
          status: 503,
          headers: { "Content-Type": "application/json" },
        }
      );
    }
  }

  return new Response("Not Found", { status: 404 });
};

Deno.serve({ port: 3000 }, handler);
```

